// =========================================
//  Store Data & Rendering
// =========================================
let storeItems = [
    {
        name: '服从胶囊',
        description: '大幅降低目标意志力，持续 2 小时。对部分高级义体无效。',
        price: 500,
        icon: 'ph-pills',
        color: 'var(--color-pink)',
        isHot: true
    },
    {
        name: '记忆覆写芯片',
        description: '短时间篡改目标近期的某段记忆，有一定风险导致脑神经损伤。',
        price: 1200,
        icon: 'ph-microchip',
        color: '#3b82f6',
        isHot: false
    },
    {
        name: 'VIP 通行证',
        description: '自由出入上层区的专属伪造身份证明。72小时内有效。',
        price: 5000,
        icon: 'ph-shield-star',
        color: 'var(--color-gold)',
        isHot: false
    },
    {
        name: '盲盒补给',
        description: '随机获取一件道具或者二手义体组件，看你的运气了。',
        price: 200,
        icon: 'ph-gift',
        color: 'var(--color-text-muted)',
        isHot: false
    }
];

function renderStoreItems() {
    const grid = document.getElementById('store-item-grid');
    if (!grid) return;

    grid.innerHTML = ''; // Clear existing items

    storeItems.forEach((item, index) => {
        const itemEl = document.createElement('div');
        itemEl.className = 'store-item';
        itemEl.style.cssText = `
            background: rgba(0,0,0,0.5);
            border: 1px solid ${item.isHot ? 'rgba(251, 191, 36, 0.4)' : 'var(--color-border)'};
            border-radius: 8px;
            padding: 1.2rem;
            text-align: center;
            position: relative;
            box-shadow: ${item.isHot ? 'inset 0 0 20px rgba(251, 191, 36, 0.05)' : 'none'};
            display: flex;
            flex-direction: column;
        `;

        itemEl.innerHTML = `
            ${item.isHot ? `<div style="position: absolute; top: 10px; left: 10px;"><span class="badge" style="background: rgba(239, 68, 68, 0.2); color: #ef4444; border: 1px solid rgba(239, 68, 68, 0.3); font-size: 0.65rem;">热销</span></div>` : ''}

            <div style="flex-grow: 1;">
                <div style="font-size: 2.8rem; color: ${item.color}; margin-bottom: 0.8rem; margin-top: 1rem; filter: ${item.color === 'var(--color-pink)' || item.color === 'var(--color-gold)' ? `drop-shadow(0 0 8px ${item.color})` : 'none'};"><i class="ph ${item.icon}"></i></div>
                <div style="font-size: 1rem; font-weight: 600; color: var(--color-text-main); margin-bottom: 0.4rem;">${item.name}</div>
                <div style="font-size: 0.8rem; color: var(--color-text-muted); margin-bottom: 1.2rem; line-height: 1.5;">${item.description}</div>
            </div>

            <div>
                <button class="buy-btn" style="width: 100%; background: rgba(251, 191, 36, 0.1); border: 1px solid var(--color-gold); color: var(--color-gold); padding: 0.6rem; border-radius: 6px; cursor: pointer; font-weight: 600; display: flex; justify-content: center; align-items: center; gap: 0.4rem; transition: var(--transition-smooth); margin-bottom: 0.5rem;"><i class="ph ph-coin"></i> ${item.price} 兑换</button>
                <div class="actions" style="display: flex; gap: 0.5rem;">
                    <button class="edit-btn" style="width: 100%; background: transparent; border: 1px solid var(--color-border); color: var(--color-text-muted); padding: 0.4rem; border-radius: 6px; cursor: pointer; font-weight: 600; font-size: 0.75rem;">编辑</button>
                    <button class="delete-btn" style="width: 100%; background: transparent; border: 1px solid var(--color-border); color: var(--color-text-muted); padding: 0.4rem; border-radius: 6px; cursor: pointer; font-weight: 600; font-size: 0.75rem;">删除</button>
                </div>
            </div>
        `;

        itemEl.querySelector('.delete-btn').addEventListener('click', () => {
            if (confirm(`确定要删除商品 "${item.name}" 吗？`)) {
                storeItems.splice(index, 1);
                renderStoreItems();
            }
        });

        itemEl.querySelector('.edit-btn').addEventListener('click', () => {
            openItemEditor(index);
        });

        grid.appendChild(itemEl);
    });
}

// =========================================
//  Modal Logic
// =========================================
function openItemEditor(index = null) {
    const modal = document.getElementById('item-editor-modal');
    const title = document.getElementById('modal-title');
    const nameInput = document.getElementById('item-name');
    const descInput = document.getElementById('item-desc');
    const priceInput = document.getElementById('item-price');
    const indexInput = document.getElementById('edit-item-index');

    if (index !== null) {
        // Editing existing item
        const item = storeItems[index];
        title.textContent = '编辑商品';
        nameInput.value = item.name;
        descInput.value = item.description;
        priceInput.value = item.price;
        indexInput.value = index;
    } else {
        // Adding new item
        title.textContent = '上架新商品';
        nameInput.value = '';
        descInput.value = '';
        priceInput.value = '';
        indexInput.value = '';
    }

    modal.style.display = 'flex';
}

function closeItemEditor() {
    const modal = document.getElementById('item-editor-modal');
    modal.style.display = 'none';
}

function saveItem() {
    const nameInput = document.getElementById('item-name');
    const descInput = document.getElementById('item-desc');
    const priceInput = document.getElementById('item-price');
    const indexInput = document.getElementById('edit-item-index');

    const name = nameInput.value.trim();
    if (!name) {
        alert('请输入商品名称');
        return;
    }

    const newItem = {
        name: name,
        description: descInput.value.trim(),
        price: parseInt(priceInput.value) || 0,
        // Default values for new items
        icon: 'ph-question',
        color: 'var(--color-text-muted)',
        isHot: false
    };

    if (indexInput.value !== '') {
        // Update existing item
        const index = parseInt(indexInput.value);
        const oldItem = storeItems[index];
        storeItems[index] = { ...oldItem, ...newItem }; // Preserve icon, color etc. if not edited
    } else {
        // Add new item
        storeItems.push(newItem);
    }

    renderStoreItems();
    closeItemEditor();
}


function initializeUI() {
    // --- Tab Switching Logic ---
    const tabBtns = document.querySelectorAll('.tab-btn');
    const tabContents = document.querySelectorAll('.tab-content');

    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            // Remove active class from all
            tabBtns.forEach(b => b.classList.remove('active'));
            tabContents.forEach(c => c.classList.remove('active'));

            // Add active class to clicked tab and corresponding content
            btn.classList.add('active');
            const targetId = btn.getAttribute('data-target');
            document.getElementById(targetId).classList.add('active');
        });
    });

    // --- Store Drawer Logic ---
    const storeDrawer = document.getElementById('store-drawer');
    const openStoreBtn = document.getElementById('open-store-btn');
    const closeStoreBtn = document.getElementById('close-store-btn');

    if (openStoreBtn) {
        openStoreBtn.addEventListener('click', () => {
            storeDrawer.style.transform = 'translateY(0)';
        });
    }

    if (closeStoreBtn) {
        closeStoreBtn.addEventListener('click', () => {
            storeDrawer.style.transform = 'translateY(100%)';
        });

        closeStoreBtn.addEventListener('mouseenter', () => {
            closeStoreBtn.style.background = 'rgba(255, 255, 255, 0.2)';
            closeStoreBtn.style.color = 'var(--color-pink)';
        });

        closeStoreBtn.addEventListener('mouseleave', () => {
            closeStoreBtn.style.background = 'rgba(255, 255, 255, 0.1)';
            closeStoreBtn.style.color = 'var(--color-text-main)';
        });
    }

    // --- Initial Render ---
    renderStoreItems();

    // --- Modal Event Listeners ---
    document.getElementById('add-item-btn').addEventListener('click', () => openItemEditor());
    document.getElementById('cancel-edit-btn').addEventListener('click', closeItemEditor);
    document.getElementById('save-item-btn').addEventListener('click', saveItem);
}

// Expose the function to the global scope
window.initializeDashboardUI = initializeUI;

// Also run it on initial load, in case the script is loaded directly
document.addEventListener('DOMContentLoaded', () => {
    initializeUI();
});
